import { Component, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute } from '@angular/router';
import { SiteviewService } from '../../../core/services/siteview.service';

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './dashboard.component.html',
  styleUrl: './dashboard.component.css',
})
export class DashboardComponent {
  private readonly projectId =
    this.route.parent?.snapshot.paramMap.get('id') ?? '';

  readonly dash = computed(() => this.sv.getDashboard(this.projectId));
  readonly pid = this.projectId;

  constructor(
    private sv: SiteviewService,
    private route: ActivatedRoute,
  ) {}

  healthClass(pct: number): string {
    if (pct >= 75) return 'good';
    if (pct >= 50) return 'warn';
    return 'bad';
  }

  usd(cents: number): string {
    return (cents / 100).toLocaleString('en-US', {
      style: 'currency',
      currency: 'USD',
      maximumFractionDigits: 0,
    });
  }

  variancePct(planned: number, actual: number): number {
    if (!planned) return 0;
    return Math.round(((actual - planned) / planned) * 100);
  }

  countOver(d: { phaseVariances: { over: boolean }[] }): number {
    return d.phaseVariances.filter((v) => v.over).length;
  }
}
